static const uint8_t * clamp8 = clamp8_lut + 512;

static inline uint16_t rb16(uint8_t *p)
{
	return (uint16_t)(((unsigned)p[0] << 8) | p[1]);
}

static inline uint32_t rb24(uint8_t *p)
{
	return ((uint32_t)p[0] << 16) | ((uint32_t)p[1] << 8) | (uint32_t)p[2];
}

static inline uint32_t rb32(uint8_t *p)
{
	return ((uint32_t)p[0] << 24) | ((uint32_t)p[1] << 16) | ((uint32_t)p[2] << 8) | (uint32_t)p[3];
}

static inline uint32_t yuv_to_rgba32(int y, int cb, int cr)
{
	int r = y + ((cr * 22970) >> 14);
	int g = y - ((cb * 5638 + cr * 11700) >> 14);
	int b = y + ((cb * 29032) >> 14);
	return ((uint32_t)clamp8[b]) | ((uint32_t)clamp8[g] << 8) | ((uint32_t)clamp8[r] << 16) | 0xFF000000u;
}

static inline void paint_v1(uint32_t * rgba, int stride, int bx, int by, struct cinepak_cv_t * e)
{
	uint32_t * row0 = rgba + by * stride + bx;
	uint32_t * row1 = row0 + stride;
	uint32_t * row2 = row1 + stride;
	uint32_t * row3 = row2 + stride;
	uint32_t c0 = e->rgba[0], c1 = e->rgba[1], c2 = e->rgba[2], c3 = e->rgba[3];

	row0[0] = c0; row0[1] = c0; row0[2] = c1; row0[3] = c1;
	row1[0] = c0; row1[1] = c0; row1[2] = c1; row1[3] = c1;
	row2[0] = c2; row2[1] = c2; row2[2] = c3; row2[3] = c3;
	row3[0] = c2; row3[1] = c2; row3[2] = c3; row3[3] = c3;
}

static inline void paint_v4(uint32_t * rgba, int stride, int bx, int by, struct cinepak_cv_t * e0, struct cinepak_cv_t * e1, struct cinepak_cv_t * e2, struct cinepak_cv_t * e3)
{
	uint32_t * row0 = rgba + by * stride + bx;
	uint32_t * row1 = row0 + stride;
	uint32_t * row2 = row1 + stride;
	uint32_t * row3 = row2 + stride;
	uint32_t * c0 = e0->rgba, * c1 = e1->rgba, * c2 = e2->rgba, * c3 = e3->rgba;

	row0[0] = c0[0]; row0[1] = c0[1]; row0[2] = c1[0]; row0[3] = c1[1];
	row1[0] = c0[2]; row1[1] = c0[3]; row1[2] = c1[2]; row1[3] = c1[3];
	row2[0] = c2[0]; row2[1] = c2[1]; row2[2] = c3[0]; row2[3] = c3[1];
	row3[0] = c2[2]; row3[1] = c2[3]; row3[2] = c3[2]; row3[3] = c3[3];
}

static void load_codebook(struct cinepak_cv_t * cb, uint8_t * data, int size, int partial, int y_only)
{
	uint8_t * p = data;
	uint8_t * end = data + size;
	uint32_t flags = 0;
	uint32_t mask = 0;
	int n = y_only ? 4 : 6;

	for(int i = 0; i < 256; ++i)
	{
		if(partial)
		{
			if(!(mask >>= 1))
			{
				if(p + 4 > end)
					return;
				flags = rb32(p);
				p += 4;
				mask = 0x80000000u;
			}
			if(!(flags & mask))
				continue;
		}

		if(p + n > end)
			return;
		int y0 = (int)p[0], y1 = (int)p[1], y2 = (int)p[2], y3 = (int)p[3];
		int cb_i = y_only ? 0 : (int)(int8_t)p[4];
		int cr_i = y_only ? 0 : (int)(int8_t)p[5];
		cb[i].rgba[0] = yuv_to_rgba32(y0, cb_i, cr_i);
		cb[i].rgba[1] = yuv_to_rgba32(y1, cb_i, cr_i);
		cb[i].rgba[2] = yuv_to_rgba32(y2, cb_i, cr_i);
		cb[i].rgba[3] = yuv_to_rgba32(y3, cb_i, cr_i);
		p += n;
	}
}

static void decode_vectors(struct cinepak_ctx_t * ctx, uint8_t * data, int size, int x1, int x2, int y1, int y2, int vec_mode, struct cinepak_cv_t * v1_decode, struct cinepak_cv_t * v4_decode)
{
	uint8_t * p = data;
	uint8_t * end = data + size;
	uint32_t flags = 0;
	int flags_b = 0;
	uint32_t * frame = ctx->frame;
	int w = (int)ctx->width;
	int h = (int)ctx->height;

	if(x1 < 0)
		x1 = 0;
	if(y1 < 0)
		y1 = 0;
	if(x2 > w)
		x2 = w;
	if(y2 > h)
		y2 = h;
	if(x1 >= x2 || y1 >= y2)
		return;

	for(int by = y1; by < y2; by += 4)
	{
		for(int bx = x1; bx < x2; bx += 4)
		{
			if(vec_mode & 1)
			{
				if(!flags_b)
				{
					if(p + 4 > end)
						return;
					flags = rb32(p);
					p += 4;
					flags_b = 32;
				}
				--flags_b;
				if(!(flags & 0x80000000u))
				{
					flags <<= 1;
					continue;
				}
				flags <<= 1;
			}

			int is_v4;
			if(vec_mode & 2)
			{
				is_v4 = 0;
			}
			else
			{
				if(!flags_b)
				{
					if(p + 4 > end)
						return;
					flags = rb32(p);
					p += 4;
					flags_b = 32;
				}
				--flags_b;
				is_v4 = !!(flags & 0x80000000u);
				flags <<= 1;
			}

			if(is_v4)
			{
				if(p + 4 > end)
					return;
				paint_v4(frame, w, bx, by, &v4_decode[p[0]], &v4_decode[p[1]], &v4_decode[p[2]], &v4_decode[p[3]]);
				p += 4;
			}
			else
			{
				if(p >= end)
					return;
				paint_v1(frame, w, bx, by, &v1_decode[*p++]);
			}
		}
	}
}

static void cinepak_init(struct cinepak_ctx_t * ctx, uint16_t width, uint16_t height, uint32_t * frame, uint32_t fsize)
{
	ctx->width = width;
	ctx->height = height;
	ctx->frame = frame;
	ctx->fsize = fsize;
}

static void cinepak_reset(struct cinepak_ctx_t * ctx)
{
	xos_memset(ctx->v1, 0, sizeof(ctx->v1));
	xos_memset(ctx->v4, 0, sizeof(ctx->v4));
	xos_memset(ctx->frame, 0, ctx->fsize);
}

static int cinepak_decode(struct cinepak_ctx_t * ctx, uint8_t * data, int size)
{
	if(!ctx || !data || size < 10)
		return 0;

	uint8_t frame_flags = data[0];
	uint32_t frame_size = rb24(data + 1);
	uint16_t num_strips = rb16(data + 8);
	int y0 = 0;

	if((int)frame_size > size)
		frame_size = (uint32_t)size;

	if(frame_flags & 1)
	{
		xos_memset(ctx->v1, 0, sizeof(ctx->v1));
		xos_memset(ctx->v4, 0, sizeof(ctx->v4));
	}

	uint8_t * p = data + 10;
	uint8_t * end = data + frame_size;

	if(num_strips > 32)
		num_strips = 32;

	for(int s = 0; s < (int)num_strips && p + 12 <= end; ++s)
	{
		uint16_t strip_id = rb16(p);
		uint16_t strip_size = rb16(p + 2);
		int strip_y1 = (int)rb16(p + 4);
		int strip_x1 = (int)rb16(p + 6);
		int strip_y2 = (int)rb16(p + 8);
		int strip_x2 = (int)rb16(p + 10);

		if(strip_size < 12)
			return 0;

		if(!strip_y1)
			strip_y1 = y0;

		if((frame_flags & 1) && !(strip_id & 0x0100))
			strip_y2 = (int)rb16(p + 8);
		else
			strip_y2 = (strip_y1 = y0) + (int)rb16(p + 8);

		uint8_t * strip_end = p + strip_size;
		if(strip_end > end)
			strip_end = end;
		p += 12;

		while(p + 4 <= strip_end)
		{
			uint8_t chunk_id = p[0];
			uint32_t chunk_size = rb24(p + 1);

			if(chunk_size < 4)
				break;

			uint8_t *cdata = p + 4;
			int csize = (int)chunk_size - 4;
			if(csize < 0 || cdata + csize > strip_end)
				break;

			switch(chunk_id)
			{
			case 0x20:
				load_codebook(ctx->v4, cdata, csize, 0, 0);
				break;
			case 0x21:
				load_codebook(ctx->v4, cdata, csize, 1, 0);
				break;
			case 0x24:
				load_codebook(ctx->v4, cdata, csize, 0, 1);
				break;
			case 0x25:
				load_codebook(ctx->v4, cdata, csize, 1, 1);
				break;
			case 0x22:
				load_codebook(ctx->v1, cdata, csize, 0, 0);
				break;
			case 0x23:
				load_codebook(ctx->v1, cdata, csize, 1, 0);
				break;
			case 0x26:
				load_codebook(ctx->v1, cdata, csize, 0, 1);
				break;
			case 0x27:
				load_codebook(ctx->v1, cdata, csize, 1, 1);
				break;
			case 0x30:
			case 0x31:
			case 0x32:
				decode_vectors(ctx, cdata, csize, strip_x1, strip_x2, strip_y1, strip_y2, (int)(chunk_id & 0x03), ctx->v1, ctx->v4);
				break;
			default:
				break;
			}

			p += chunk_size;
		}

		p = strip_end;
		y0 = strip_y2;
	}
	return 1;
}

struct xaf_header_t {
	uint8_t magic[4];
	uint16_t width;
	uint16_t height;
	uint32_t nframes;
	uint8_t fps;
	uint8_t reserved[3];
};

static int parse_header(uint8_t * data, int size, struct xaf_header_t * hdr)
{
	if(!data || (size < 16))
		return 0;
	if(data[0] != 'X' || data[1] != 'A' || data[2] != 'F' || data[3] != 0)
		return 0;
	hdr->width = data[4] | (data[5] << 8);
	hdr->height = data[6] | (data[7] << 8);
	hdr->nframes = data[8] | (data[9] << 8) | (data[10] << 16) | (data[11] << 24);
	hdr->fps = data[12];
	return 1;
}

static int read_u32_at(uint8_t * data, uint32_t size, uint32_t pos, uint32_t * out)
{
	if(pos + 4 > size)
		return 0;
	*out = (uint32_t)(data[pos] | (data[pos + 1] << 8) | (data[pos + 2] << 16) | (data[pos + 3] << 24));
	return 1;
}

struct xaf_t * xaf_alloc(uint8_t * data, uint32_t size)
{
	struct xaf_header_t hdr;

	if(!parse_header(data, size, &hdr))
		return NULL;
	if(hdr.width == 0 || hdr.height == 0 || hdr.nframes == 0 || hdr.fps == 0)
		return NULL;

	struct xaf_t * ctx = (struct xaf_t *)xos_mem_malloc(sizeof(struct xaf_t));
	if(!ctx)
		return NULL;

	ctx->width = hdr.width;
	ctx->height = hdr.height;
	ctx->nframes = hdr.nframes;
	ctx->fps = hdr.fps;
	ctx->findex = 0;
	ctx->data = data;
	ctx->size = size;
	ctx->pos = 16;
	ctx->fsize = (hdr.height + 4) * hdr.width * 4;
	ctx->frame = xos_mem_malloc(ctx->fsize);
	if(!ctx->frame)
	{
		xos_mem_free(ctx);
		return NULL;
	}
	cinepak_init(&ctx->cinepak, hdr.width, hdr.height, ctx->frame, ctx->fsize);
	cinepak_reset(&ctx->cinepak);

	return ctx;
}

void xaf_free(struct xaf_t *ctx)
{
	if(ctx)
	{
		xos_mem_free(ctx->frame);
		xos_mem_free(ctx);
	}
}

void xaf_reset(struct xaf_t * ctx)
{
	if(ctx)
	{
		ctx->pos = 16;
		ctx->findex = 0;
		cinepak_reset(&ctx->cinepak);
	}
}

uint32_t * xaf_next(struct xaf_t * ctx)
{
	if(!ctx)
		return NULL;
	if(ctx->findex >= ctx->nframes)
		return NULL;

	uint32_t frame_size;
	if(!read_u32_at(ctx->data, ctx->size, ctx->pos, &frame_size))
		return NULL;
	ctx->pos += 4;

	if(frame_size == 0)
		return NULL;
	if(ctx->pos + frame_size > ctx->size)
		return NULL;

	if(!cinepak_decode(&ctx->cinepak, ctx->data + ctx->pos, frame_size))
		return NULL;

	ctx->pos += frame_size;
	ctx->findex++;
	return ctx->frame;
}
